using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Build the AI client with automatic function invocation
// ---------------------------------------------------------------------------

var notepad = new Notepad();

IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearch.SearchAsync),
        AIFunctionFactory.Create(WebSearch.FetchPageAsync),
        AIFunctionFactory.Create(notepad.TakeNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ]
};

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║         🔍  Research Agent  🔍          ║");
Console.WriteLine("╠══════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research, or 'quit'.  ║");
Console.WriteLine("╚══════════════════════════════════════════╝");

while (true)
{
    Console.Write("\n> ");
    var input = Console.ReadLine();

    if (string.IsNullOrWhiteSpace(input))
        continue;
    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notepad.Clear();

    List<ChatMessage> messages =
    [
        new(ChatRole.System, """
            You are a research agent. Follow these steps for every request:
            1. Search the web for the topic using multiple queries if needed.
            2. Fetch promising web pages to gather detailed information.
            3. Take notes on every key finding as you go.
            4. Review your notes, then produce a well-structured summary with
               an introduction, key findings (with sources), and a conclusion.
            Be thorough and cite your sources.
            """),
        new(ChatRole.User, $"Research the following topic and provide a summary:\n\n{input}")
    ];

    Console.WriteLine("\nResearching… (the agent may call tools several times)\n");

    var response = await client.GetResponseAsync(messages, chatOptions);

    Console.WriteLine(response.Text);
}

// ---------------------------------------------------------------------------
// Web-search tool
// ---------------------------------------------------------------------------

static partial class WebSearch
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } }
    };

    [Description("Search the web for information. Returns titles, URLs, and snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await Http.GetStringAsync(url);

            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var sb = new StringBuilder();

            var abstractText = root.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrEmpty(abstractText))
            {
                sb.AppendLine($"## Summary\n{abstractText}");
                sb.AppendLine($"Source: {root.GetProperty("AbstractURL").GetString()}\n");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                int count = 0;
                foreach (var topic in topics.EnumerateArray())
                {
                    if (count >= 8) break;
                    if (topic.TryGetProperty("Text", out var text))
                    {
                        sb.AppendLine($"- {text.GetString()}");
                        if (topic.TryGetProperty("FirstURL", out var firstUrl))
                            sb.AppendLine($"  URL: {firstUrl.GetString()}");
                        count++;
                    }
                }
            }

            return sb.Length > 0
                ? sb.ToString()
                : "No results found. Try a different query or fetch a specific URL directly.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try fetching a specific URL instead.";
        }
    }

    [Description("Fetch the text content of a web page at the given URL.")]
    public static async Task<string> FetchPageAsync(
        [Description("The full URL to fetch")] string url)
    {
        try
        {
            var html = await Http.GetStringAsync(url);

            // Strip scripts, styles, and tags to get plain text
            html = ScriptPattern().Replace(html, " ");
            html = StylePattern().Replace(html, " ");
            html = TagPattern().Replace(html, " ");
            html = WhitespacePattern().Replace(html, " ");
            html = WebUtility.HtmlDecode(html).Trim();

            const int maxLen = 6000;
            if (html.Length > maxLen)
                html = html[..maxLen] + "\n\n[…content truncated]";

            return html;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    [GeneratedRegex(@"<script[^>]*>[\s\S]*?</script>", RegexOptions.IgnoreCase)]
    private static partial Regex ScriptPattern();

    [GeneratedRegex(@"<style[^>]*>[\s\S]*?</style>", RegexOptions.IgnoreCase)]
    private static partial Regex StylePattern();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagPattern();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespacePattern();
}

// ---------------------------------------------------------------------------
// Note-taking tool
// ---------------------------------------------------------------------------

class Notepad
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Save a research note. Use this to record each key finding during research.")]
    public string TakeNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝  Note saved: {title}");
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes to compile a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note #{i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

