     [Description("Save a research note. Use this to record each key finding during research.")]
     public string TakeNote(
         [Description("Short title for the note")] string title,
         [Description("Detailed content of the note")] string content)
     {
         _notes.Add((title, content));
         Console.WriteLine($"  📝  Note saved: {title}");
         return $"Note #{_notes.Count} saved: \"{title}\"";
     }

     [Description("Retrieve all saved research notes to compile a summary.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes have been saved yet.";

         var sb = new StringBuilder();
         for (var i = 0; i < _notes.Count; i++)
         {
             sb.AppendLine($"--- Note #{i + 1}: {_notes[i].Title} ---");
             sb.AppendLine(_notes[i].Content);
             sb.AppendLine();
         }
         return sb.ToString();
     }

     public void Clear() => _notes.Clear();
 }

